import math

def create_gaussian_kernel(size, sigma):
    pad = size // 2
    kernel = [[0] * size for _ in range(size)]
    sum_kernel = 0

    for i in range(-pad, pad + 1):
        for j in range(-pad, pad + 1):
            # Gaussian function
            exponent = -(i*i + j*j) / (2 * sigma * sigma)
            kernel[i + pad][j + pad] = math.exp(exponent)
            sum_kernel += kernel[i + pad][j + pad]

    # Normalize kernel
    for i in range(size):
        for j in range(size):
            kernel[i][j] /= sum_kernel

    return kernel

def apply_gaussian_blur(image, kernel_size, sigma):
    kernel = create_gaussian_kernel(kernel_size, sigma)
    # Apply convolution with Gaussian kernel
    # Similar to mean filter but with Gaussian weights
    rows, cols = len(image), len(image[0])
    pad = kernel_size // 2
    output = [[0] * cols for _ in range(rows)]

    for i in range(pad, rows - pad):
        for j in range(pad, cols - pad):
            sum_value = 0
            for ki in range(kernel_size):
                for kj in range(kernel_size):
                    sum_value += kernel[ki][kj] * image[i + ki - pad][j + kj - pad]
            output[i][j] = int(sum_value)

    return output

